local function dec_bxor(a, b)
    local p = 1
    local c = 0
    while a > 0 or b > 0 do
        local ra = a % 2
        local rb = b % 2
        if ra ~= rb then
            c = c + p
        end
        a = (a - ra) / 2
        b = (b - rb) / 2
        p = p * 2
    end
    return c
end


local function dec_b64(data)
    local b = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
    data = string.gsub(data, '[^'..b..'=]', '')
    return (data:gsub('.', function(x)
        if (x == '=') then
            return ''
        end
        local r = ''
        local f = (b:find(x) - 1)
        for i = 6, 1, -1 do
            local math_calc = f % 2^i - f % 2^(i-1)
            if math_calc > 0 then
                r = r .. '1'
            else
                r = r .. '0'
            end
        end
        return r
    end):gsub('%d%d%d?%d?%d?%d?%d?%d?', function(x)
        if (#x ~= 8) then
            return ''
        end
        local c = 0
        for i = 1, 8 do
            local sub_char = x:sub(i, i)
            if sub_char == '1' then
                c = c + 2^(8 - i)
            else
                c = c + 0
            end
        end
        return string.char(c)
    end))
end


local function dec_hex(data)
    local result = string.gsub(data, '..', function(cc)
        return string.char(tonumber(cc, 16))
    end)
    return result
end


local function dec_rev(data)
    return string.reverse(data)
end


